#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

#define RANDOM_MAX 2147483647

extern double wtime(void);
extern int num_omp_threads;

__device__
float euclid_dist_2_device(float *pt1, float *pt2, int numdims)
{
    int i;
    float ans = 0.0;
    for (i = 0; i < numdims; i)
        ans += (pt1[i] - pt2[i]) * (pt1[i] - pt2[i]);
    return ans;
}

__global__
void find_nearest_point_kernel(float *feature, float **clusters, int *membership,
                               int npoints, int nfeatures, int nclusters, float *delta)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    int index = 0;
    float min_dist = FLT_MAX;

    for (int j = 0; j < nclusters; j++) {
        float dist = 0.0;
        for (int k = 0; k < nfeatures; k++) {
            float diff = feature[i * nfeatures + k] - clusters[j][k];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = j;
        }
    }

    if (membership[i] != index) {
        *delta += 1.0;
    }
    membership[i] = index;
}

__global__
void update_centers_kernel(float *feature, int *membership, float **partial_new_centers,
                           int *partial_new_centers_len, int npoints, int nfeatures, int nclusters)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    int index = membership[i];
    partial_new_centers_len[index]++;
    for (int j = 0; j < nfeatures; j++) {
        partial_new_centers[index][j] += feature[i * nfeatures + j];
    }
}

int cluster(int      numObjects,      
            int      numAttributes,   
            float  **attributes,                  
            int      nclusters,
            float    threshold,       
            float ***cluster_centres)
{
    int    *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    tmp_cluster_centres = kmeans_clustering(attributes,
                                            numAttributes,
                                            numObjects,
                                            nclusters,
                                            threshold,
                                            membership);      

    if (*cluster_centres) {
		free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}

float** kmeans_clustering(float **feature,    
                          int     nfeatures,
                          int     npoints,
                          int     nclusters,
                          float   threshold,
                          int    *membership) 
{
    int      i, j, k, n = 0, index, loop = 0;
    int     *new_centers_len;
    float  **new_centers;
    float  **clusters;
    float    delta;
    double   timing;
    int      nthreads;
    int    **partial_new_centers_len;
    float ***partial_new_centers;

    nthreads = num_omp_threads;

    clusters    = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*)  malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    for (i = 0; i < nclusters; i) {
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    new_centers    = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    partial_new_centers_len    = (int**) malloc(nthreads * sizeof(int*));
    partial_new_centers_len[0] = (int*)  calloc(nthreads * nclusters, sizeof(int));
    for (i = 1; i < nthreads; i)
        partial_new_centers_len[i] = partial_new_centers_len[i-1] + nclusters;

    partial_new_centers    = (float***) malloc(nthreads * sizeof(float**));
    partial_new_centers[0] = (float**) malloc(nthreads * nclusters * sizeof(float*));
    for (i = 1; i < nthreads; i++)
        partial_new_centers[i] = partial_new_centers[i-1] + nclusters;

    for (i = 0; i < nthreads; i++) {
        for (j = 0; j < nclusters; j++)
            partial_new_centers[i][j] = (float*) calloc(nfeatures, sizeof(float));
    }

    printf("num of threads = %d\n", num_omp_threads);

    int num_blocks = (npoints + 255) / 256;
    int threads_per_block = 256;

    float *d_feature;
    float **d_clusters;
    int *d_membership;
    float *d_delta;

    cudaMalloc(&d_feature, npoints * nfeatures * sizeof(float));
    cudaMalloc(&d_clusters, nclusters * nfeatures * sizeof(float));
    cudaMalloc(&d_membership, npoints * sizeof(int));
    cudaMalloc(&d_delta, sizeof(float));

    float *feature_flat = feature[0];
    cudaMemcpy(d_feature, feature_flat, npoints * nfeatures * sizeof(float), cudaMemcpyHostToDevice);

    do {
        delta = 0.0;
        cudaMemset(d_delta, 0, sizeof(float));
        cudaMemset(d_membership, -1, npoints * sizeof(int));

        cudaMemcpy(d_clusters, clusters[0], nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice);

        find_nearest_point_kernel<<<num_blocks, threads_per_block>>>(
            d_feature, d_clusters, d_membership, npoints, nfeatures, nclusters, d_delta);

        cudaMemset(partial_new_centers_len[0], 0, nthreads * nclusters * sizeof(int));
        for (i = 0; i < nthreads; i++) {
            for (j = 0; j < nclusters; j++) {
                memset(partial_new_centers[i][j], 0, nfeatures * sizeof(float));
            }
        }

        update_centers_kernel<<<num_blocks, threads_per_block>>>(
            d_feature, d_membership, partial_new_centers[0], 
            partial_new_centers_len[0], npoints, nfeatures, nclusters);

        cudaMemcpy(&delta, d_delta, sizeof(float), cudaMemcpyDeviceToHost);
        cudaMemcpy(d_membership, membership, npoints * sizeof(int), cudaMemcpyDeviceToHost);
        cudaMemcpy(membership, d_membership, npoints * sizeof(int), cudaMemcpyDeviceToHost);

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nthreads; j++) {
                new_centers_len[i] += partial_new_centers_len[j][i];
                partial_new_centers_len[j][i] = 0;
                for (k = 0; k < nfeatures; k++) {
                    new_centers[i][k] += partial_new_centers[j][i][k];
                    partial_new_centers[j][i][k] = 0.0;
                }
            }
        }

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0;
            }
            new_centers_len[i] = 0;
        }

    } while (delta > threshold && loop++ < 500);

    cudaFree(d_feature);
    cudaFree(d_clusters);
    cudaFree(d_membership);
    cudaFree(d_delta);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

